onClick:
{{
JSFacturaCompra.validarFactura()

?

(
    appsmith.store.modoFC === "MODIFICAR"

    ?

qryFCModificar.run(

    async (data) => {

        await storeValue(
            "ultimaFCCreada",
            appsmith.store.idFCModificar
        );

        showAlert(
            "Factura #" +
            data[0].id_factura_compra +
            " modificada correctamente",
            "success"
        );

        JSFacturaCompra.nuevaFactura();

    }

)

    :

qryFCCrear.run(
    async (data) => {

        await storeValue(
            "ultimaFCCreada",
            data[0].id_factura_compra
        );

        showAlert(
            "Factura #" +
            data[0].id_factura_compra +
            " creada correctamente",
            "success"
        );

        JSFacturaCompra.limpiarFormulario();

    }
)

)

:

null
}}
